#include "Finder.h"
#include <chrono>
#include <iostream>
using namespace std;

class TestCases
{
private: 
    // Test cases
    string s1_t1 = "abcdefghijklmnopqrstuvwxyz";
    string s2_t1 = "lmnop";

    string s1_t2 = "aaabbcd";
    string s2_t2 = "aadbcd";

    // s1 = length 1000, s2 = length 400
    string s1_t3 = "";
    string s2_t3 = "";

    // s1 = length 50000 (10^4 * 5), s2 length = 10000 (10^4)
    string s1_t4 = "";
    string s2_t4 = "";
    
    std::chrono::time_point<std::chrono::high_resolution_clock> init = std::chrono::high_resolution_clock::now();
    std::chrono::time_point<std::chrono::high_resolution_clock> finish = std::chrono::high_resolution_clock::now();
public:
    TestCases(Finder& f) {
        // Test cases solutions
        init = std::chrono::high_resolution_clock::now();
        vector<int> sol_t1 = f.unOpfindSubstrings(s1_t1, s2_t1);
        finish = std::chrono::high_resolution_clock::now();
        std::chrono::duration<double> elapsed1 = finish - init;

        init = std::chrono::high_resolution_clock::now();
        vector<int> sol_t2 = f.unOpfindSubstrings(s1_t2, s2_t2);
        finish = std::chrono::high_resolution_clock::now();
        std::chrono::duration<double> elapsed2 = finish - init;

        init = std::chrono::high_resolution_clock::now();
        vector<int> sol_t3 = f.unOpfindSubstrings(s1_t3, s2_t3);
        finish = std::chrono::high_resolution_clock::now();
        std::chrono::duration<double> elapsed3 = finish - init;

        init = std::chrono::high_resolution_clock::now();
        vector<int> sol_t4 = f.unOpfindSubstrings(s1_t4, s2_t4);
        finish = std::chrono::high_resolution_clock::now();
        std::chrono::duration<double> elapsed7 = finish - init;

        cout << "---Solutions calculation time---\nt1: " << elapsed1.count() << "\nt2: " << elapsed2.count() << "\nt3: " << elapsed3.count() << "\nt4: " << elapsed7.count() << endl;

        // Test case for answers
        init = std::chrono::high_resolution_clock::now();
        vector<int> ans1 = f.findSubstrings(s1_t1, s2_t1);
        finish = std::chrono::high_resolution_clock::now();
        std::chrono::duration<double> elapsed4 = finish - init;

        init = std::chrono::high_resolution_clock::now();
        vector<int> ans2 = f.findSubstrings(s1_t2, s2_t2);
        finish = std::chrono::high_resolution_clock::now();
        std::chrono::duration<double> elapsed5 = finish - init;

        init = std::chrono::high_resolution_clock::now();
        vector<int> ans3 = f.findSubstrings(s1_t3, s2_t3);
        finish = std::chrono::high_resolution_clock::now();
        std::chrono::duration<double> elapsed6 = finish - init;

        init = std::chrono::high_resolution_clock::now();
        vector<int> ans4 = f.findSubstrings(s1_t4, s2_t4);
        finish = std::chrono::high_resolution_clock::now();
        std::chrono::duration<double> elapsed8 = finish - init;
        
        vector<bool> correct;
        correct.push_back((ans1 == sol_t1));
        correct.push_back((ans2 == sol_t2));
        correct.push_back((ans3 == sol_t3));
        correct.push_back((ans4 == sol_t4));

        if (correct[0] == false) {
            cout << "===Error on test case 1===\nYour Out: ";
            for (int i : ans1) cout << i << " ";
            cout << "\nExpected Out: ";
            for (int i : sol_t1) cout << i << " ";
            cout << "\n======\n"; 
        }

        if (correct[1] == false) {
            cout << "===Error on test case 2===\nYour Out: ";
            for (int i : ans2) cout << i << " ";
            cout << "\nExpected Out: ";
            for (int i : sol_t2) cout << i << " ";
            cout << "\n======\n"; 
        }

        if (correct[2] == false) {
            cout << "===Error on test case 3===\nYour Out: ";
            for (int i : ans3) cout << i << " ";
            cout << "\nExpected Out: ";
            for (int i : sol_t3) cout << i << " ";
            cout << "\n======\n"; 
        }
        if (correct[3] == false) {
            cout << "===Error on test case 4===\nYour Out: ";
            for (int i : ans4) cout << i << " ";
            cout << "\nExpected Out: ";
            for (int i : sol_t4) cout << i << " ";
            cout << "\n======\n"; 
        }
        
        cout << "---Answers calculation time---\nt1: " << elapsed4.count() << ", PASS: " << (correct[0] ? "TRUE" : "FALSE") << 
        "\nt2: " << elapsed5.count() << ", PASS: " << (correct[1] ? "TRUE" : "FALSE") <<
        "\nt3: " << elapsed6.count() << ", PASS: " << (correct[2] ? "TRUE" : "FALSE") << 
        "\nt4: " << elapsed8.count() << ", PASS: " << (correct[3] ? "TRUE" : "FALSE") << endl;
        
    }

    
};

int main(void) {
    Finder f;
    // test cases
    TestCases t(f);
    return 0;
}